// Periksa token keamanan sebelum memproses.
// UBAH nilai SIBI_SECRET di bawah — harus sama dengan SIBI_TOKEN di sibi_common.py & firmware.
// Selama masih 'GANTI_TOKEN_RAHASIA', pemeriksaan DILEWATI (mode dev / tidak aktif).
const SIBI_SECRET = 'GANTI_TOKEN_RAHASIA';
const _reqHdr = ($input.first().json.headers || {});
const _token = (_reqHdr['x-sibi-token'] || '');
if (SIBI_SECRET !== 'GANTI_TOKEN_RAHASIA' && _token !== SIBI_SECRET) {
  return [{ json: { aksi: 'ERROR', perluProses: false, buffer: '', hasil: null, claudeBody: {} } }];
}

// ALUR 1 — Terima huruf dari ESP32/simulator dan rangkai jadi buffer kalimat.
// State disimpan di workflowStaticData (TANPA database eksternal).
const s = $getWorkflowStaticData('global');
s.buffer = s.buffer || "";
s.hasil = (typeof s.hasil === 'undefined') ? null : s.hasil;

const item = $input.first().json;
const body = item.body || item; // webhook v2 menaruh data POST di .body
const aksi = String(body.aksi || "").toUpperCase();
const huruf = String(body.huruf || "");

if (aksi === "HURUF") { s.buffer += huruf; }
else if (aksi === "SPASI") { s.buffer += " "; }
else if (aksi === "HAPUS") { s.buffer = s.buffer.slice(0, -1); }
// aksi "KIRIM" diproses Claude HANYA bila buffer tidak kosong (hemat biaya + aman)
const perluProses = (aksi === "KIRIM") && (s.buffer.trim().length > 0);

// Bangun body permintaan Claude di sini agar node HTTP tidak perlu escaping rumit.
// Format OpenAI-compatible (sumopod AI = proxy LiteLLM di https://ai.sumopod.com/v1).
// Instruksi ditaruh di pesan USER (model sumopod abaikan role 'system'-nya sendiri).
const instruksi = 'Kamu mesin koreksi abjad jari SIBI. Diberi rangkaian huruf kapital (mungkin salah eja/terpotong), tebak kata/kalimat Bahasa Indonesia sehari-hari yang paling masuk akal. Perbaiki ejaan, spasi, kapitalisasi, tanda baca. JANGAN bertanya, JANGAN menjelaskan, JANGAN menambah info. Keluarkan HANYA satu baris JSON valid: {"teks":"<kalimat rapi>","untuk_suara":"<kalimat tanpa tanda baca berlebih>"}';
const MODEL_AI = "claude-haiku-4-5"; // UBAH bila nama model di sumopod beda (cek: GET https://ai.sumopod.com/v1/models)
const claudeBody = {
  model: MODEL_AI,
  max_tokens: 200,
  temperature: 0.2,
  response_format: { type: "json_object" },
  messages: [
    { role: "user", content: instruksi + " Huruf: " + s.buffer }
  ]
};

return [{ json: { aksi: aksi, perluProses: perluProses, buffer: s.buffer, hasil: s.hasil, claudeBody: claudeBody } }];

// Parse balasan Claude, simpan ke staticData, kosongkan buffer.
// Mode aman/offline: bila Claude gagal atau format JSON tidak sesuai, pakai buffer apa adanya.
const s = $getWorkflowStaticData('global');
const teksDikirim = s.buffer || "";
let hasil;
try {
  let raw = $input.first().json.choices[0].message.content || "";
  const a = raw.indexOf("{"); const b = raw.lastIndexOf("}"); // buang pagar ```json``` / teks pembungkus
  if (a === -1 || b === -1) { throw new Error("tidak ada JSON di balasan"); }
  raw = raw.slice(a, b + 1);
  hasil = JSON.parse(raw);
  if (!hasil || !hasil.teks) { throw new Error("format hasil tidak sesuai"); }
  if (!hasil.untuk_suara) { hasil.untuk_suara = hasil.teks; }
} catch (e) {
  hasil = { teks: teksDikirim, untuk_suara: teksDikirim };
}
s.hasil = hasil;
s.buffer = ""; // privasi: kosongkan buffer setiap kalimat selesai
return [{ json: { ok: true, buffer: "", hasil: s.hasil, ts: Date.now() } }];

// ALUR 2 — Status untuk dashboard (polling tiap 1 detik).
const s = $getWorkflowStaticData('global');
return [{ json: { buffer: s.buffer || "", hasil: (typeof s.hasil === 'undefined' ? null : s.hasil), ts: Date.now() } }];
